CREATE OR REPLACE FUNCTION fpb_tel_get_loan_history ( as_reqno char , as_loan_group char , as_field char ) RETURNS bigint AS $body$
DECLARE

ldc_bal  sc_lon_m_loan_history.principal_balance_of_loan%type;
ldc_int  sc_lon_m_loan_history.interest_amount%type;

BEGIN
    SELECT  sum( sc_lon_m_loan_history.principal_balance_of_loan ) ,
            sum( sc_lon_m_loan_history.interest_amount )
    INTO STRICT ldc_bal , ldc_int
    FROM sc_lon_m_loan_request,
         sc_lon_m_loan_card,
         sc_lon_m_loan_history,
         sc_lon_m_rule
   WHERE ( sc_lon_m_loan_history.loan_contract_no = sc_lon_m_loan_card.loan_contract_no ) and ( sc_lon_m_loan_history.loan_requestment_no = sc_lon_m_loan_request.loan_requestment_no ) and ( sc_lon_m_rule.loan_type = sc_lon_m_loan_card.loan_type ) and
         ( sc_lon_m_loan_request.loan_requestment_no = as_reqno  AND  sc_lon_m_rule.loan_group_code = as_loan_group );
    if coalesce(ldc_bal::text, '') = '' then ldc_bal := 0;end if;
    if coalesce(ldc_int::text, '') = '' then ldc_int := 0;end if;


   case trim(both as_field )
   when 'prin' THEN
      return ldc_bal;
   when 'int' THEN
      return ldc_int;
   else
      return ldc_bal;
   end case;


END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
